// Combine the cached snapshot with 24h-history stats per service.
// Snapshot is one row; stats is one row per service name.

const snapRow = $('Read Snapshot').first()?.json;
const statsItems = $input.all().map(i => i.json);

if (!snapRow || snapRow.data == null) {
  return [{ json: {
    services: [],
    summary: { total: 0, up: 0, auth: 0, down: 0, ts: null },
    cached: false,
    cached_at: null,
    cached_age_s: null
  }}];
}

let payload = snapRow.data;
if (typeof payload === 'string') {
  try { payload = JSON.parse(payload); } catch { payload = { services: [], summary: {} }; }
}

// Index stats by service name
const statsByName = {};
for (const s of statsItems) {
  if (s && s.name) statsByName[s.name] = s;
}

const enriched = (payload.services || []).map(svc => {
  const st = statsByName[svc.name];
  return {
    ...svc,
    uptime_24h_pct: st?.uptime_pct != null ? Number(st.uptime_pct) : null,
    avg_latency_24h_ms: st?.avg_latency_ms != null ? Number(st.avg_latency_ms) : null,
    sample_count_24h: st?.sample_count != null ? Number(st.sample_count) : null,
    last_down_at: st?.last_down_unix ? new Date(Number(st.last_down_unix) * 1000).toISOString() : null
  };
});

const unix = Number(snapRow.updated_at_unix) || null;
const nowS = Math.floor(Date.now() / 1000);
const ageS = unix ? Math.max(0, nowS - unix) : null;

return [{ json: {
  ...payload,
  services: enriched,
  cached: true,
  cached_at: unix ? new Date(unix * 1000).toISOString() : null,
  cached_age_s: ageS
}}];

// Health-check the homelab service inventory in parallel.
// Source list mirrors the Drupal Links page on blackbox (/drupal/index.php/node/2).
//
// `link` is the human-friendly URL the user clicks (preserves .local mDNS names
// so browsers with Bonjour resolve them correctly). `check` is what n8n hits
// (uses IPs because the n8n container has no Avahi to resolve mDNS).
//
// Up = 2xx-4xx other than auth-required.
// Auth = 401/403 (service responding but credentials needed; counts as healthy).
// Down = network error, timeout, or 5xx.
//
// HTTPS services with self-signed certs: ignoreSSLIssues=true.

const services = [
  { name: 'Home Assistant',       link: 'http://homeassistant.local:8123/',         check: 'http://192.168.0.176:8123/',           category: 'Home' },
  { name: 'Homebridge',           link: 'http://homebridge.home.arpa:8581/',        check: 'http://homebridge.home.arpa:8581/',    category: 'Home' },
  { name: 'MyWiki',               link: 'http://piholemini.local:8080/mediawiki',   check: 'http://192.168.0.125:8080/mediawiki/api.php?action=query&meta=siteinfo&format=json', category: 'Internal' },
  { name: 'phpMyAdmin',           link: 'http://blackbox.local/phpmyadmin/',        check: 'http://192.168.0.55/phpmyadmin/',      category: 'Internal' },
  { name: 'Guacamole (blackbox)', link: 'http://blackbox.local:8080/guacamole/',    check: 'http://192.168.0.55:8080/guacamole/',  category: 'Internal' },
  { name: 'Guacamole (thevault)', link: 'http://thevault.local:8348/',              check: 'http://192.168.0.21:8348/',            category: 'Internal' },
  { name: 'LAN Speed Test',       link: 'http://blackbox.local:3000/',              check: 'http://192.168.0.55:3000/',            category: 'Internal' },
  { name: 'Diskstation',          link: 'https://thevault.local/',                  check: 'https://192.168.0.21/',                category: 'Storage' },
  { name: 'Proxmox',              link: 'https://192.168.0.200:8006/',              check: 'https://192.168.0.200:8006/',          category: 'Infra' },
  { name: 'Portainer',            link: 'http://thevault.local:9000/',              check: 'http://192.168.0.21:9000/',            category: 'Infra' },
  { name: 'Semaphore',            link: 'http://thevault.local:3000',               check: 'http://192.168.0.21:3000',             category: 'Infra' },
  { name: 'Pi-hole (main)',       link: 'http://192.168.0.225/admin/',              check: 'http://192.168.0.225/admin/',          category: 'DNS' },
  { name: 'Pi-hole (mini)',       link: 'http://192.168.0.125/admin/',              check: 'http://192.168.0.125/admin/',          category: 'DNS' },
  { name: 'Router (Synology)',    link: 'http://192.168.0.1:8000/webman/index.cgi', check: 'http://192.168.0.1:8000/',             category: 'Network' },
  { name: 'Plex',                 link: 'http://plex.local:32400/web',              check: 'http://192.168.0.222:32400/web',       category: 'Media' },
  { name: 'Tautulli',             link: 'http://plex.local:8181',                   check: 'http://192.168.0.222:8181',            category: 'Media' },
  { name: 'Sabnzbd',              link: 'http://thevault.local:8775/',              check: 'http://192.168.0.21:8775/',            category: 'Media' },
  { name: 'Sonarr',               link: 'http://thevault.local:8989/',              check: 'http://192.168.0.21:8989/',            category: 'Media' },
  { name: 'Radarr',               link: 'http://thevault.local:7878/',              check: 'http://192.168.0.21:7878/',            category: 'Media' },
  { name: 'Zabbix',               link: 'http://netmon.home.arpa/zabbix/',          check: 'http://192.168.0.150/zabbix/',         category: 'Monitoring' },
  { name: 'Grafana',              link: 'http://thevault.local:3340',               check: 'http://192.168.0.21:3340',             category: 'Monitoring' },
  { name: 'Wazuh',                link: 'https://security.home.arpa/',              check: 'https://192.168.0.223/',               category: 'Security' },
  { name: 'OpenClaw',             link: 'https://blackbox.home.arpa:8443',          check: 'https://blackbox.home.arpa:8443',      category: 'Security' }
];

const TIMEOUT_MS = 5000;
const RETRY_TIMEOUT_MS = 8000;
const RETRY_DELAY_MS = 800;

async function attempt(svc, timeoutMs) {
  const t0 = Date.now();
  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: svc.check,
      timeout: timeoutMs,
      ignoreHttpStatusErrors: true,
      skipSslCertificateValidation: true,
      rejectUnauthorized: false,
      returnFullResponse: true,
      followRedirect: false,
      maxRedirects: 0
    });
    return { ok: true, http: res.statusCode, latency_ms: Date.now() - t0 };
  } catch (e) {
    const code = e?.cause?.code || e?.code || e?.name;
    return { ok: false, error: code || (e?.message || '').slice(0, 80), latency_ms: Date.now() - t0 };
  }
}

const attemptBound = attempt.bind(this);
const sleep = (ms) => new Promise(r => setTimeout(r, ms));

const results = await Promise.all(services.map(async (svc) => {
  // First attempt (5s). If it fails, wait briefly so the underlying connection
  // pool can settle, then try once more with a longer timeout. Two clean failures
  // = really down.
  let r = await attemptBound(svc, TIMEOUT_MS);
  if (!r.ok) {
    await sleep(RETRY_DELAY_MS);
    r = await attemptBound(svc, RETRY_TIMEOUT_MS);
  }
  return { ...svc, ...r };
}));

function classify(r) {
  if (!r.ok) return 'down';
  const c = r.http;
  if (c === 401 || c === 403) return 'auth';
  if (c >= 200 && c < 500) return 'up';
  return 'down';
}

const formatted = results.map(r => ({
  name: r.name,
  url: r.link,
  category: r.category,
  status: classify(r),
  http_code: r.http || null,
  latency_ms: r.latency_ms,
  error: r.error || null
}));

const summary = {
  total: formatted.length,
  up: formatted.filter(r => r.status === 'up').length,
  auth: formatted.filter(r => r.status === 'auth').length,
  down: formatted.filter(r => r.status === 'down').length,
  ts: new Date().toISOString()
};

return [{ json: { services: formatted, summary } }];

// Build SQL strings for both the snapshot REPLACE and the history INSERT.
// SQL string-literal escape: backslash doubles, single quote doubles.
const data = $json;
const services = data.services || [];

const sqlStr = (s) => s == null
  ? 'NULL'
  : `'${String(s).replace(/\\/g, '\\\\').replace(/'/g, "''")}'`;
const sqlNum = (n) => (n == null || Number.isNaN(Number(n))) ? 'NULL' : Number(n);

const snapshotBlob = JSON.stringify(data).replace(/\\/g, '\\\\').replace(/'/g, "''");
const snapshotSql = `REPLACE INTO service_health_snapshot (id, data) VALUES (1, '${snapshotBlob}')`;

const valuesRows = services.map(s =>
  `(NOW(), ${sqlStr(s.name)}, ${sqlStr(s.status)}, ${sqlNum(s.latency_ms)}, ${sqlNum(s.http_code)}, ${sqlStr(s.error)})`
).join(',\n');

const historySql = services.length > 0
  ? `INSERT INTO service_health_history (ts, name, status, latency_ms, http_code, error) VALUES ${valuesRows}`
  : 'SELECT 1';

return [{ json: { snapshot_sql: snapshotSql, history_sql: historySql } }];

// Validate + escape the name query param. Clamp hours to [1, 168].
const q = $('GET /services/history').first()?.json?.query || {};
const name = String(q.name || '');
const hours = Math.min(168, Math.max(1, parseInt(q.hours || '24', 10) || 24));
const nameSql = name.replace(/\\/g, '\\\\').replace(/'/g, "''");
return [{ json: { name, name_sql: nameSql, hours } }];

// Combine the three upstream queries into the response shape.
// - Bucket raw points (5min if >500 samples, else 1min)
// - Detect incidents as consecutive non-up runs
// - Pull stats from Read History Stats

const params = $('Parse Name').first().json;
const points = $('Read Points').all().map(i => i.json);
const stats = $input.first()?.json || {};

const bucketSizeS = points.length > 500 ? 300 : 60;

function bucket(rows, intervalS) {
  const buckets = new Map();
  for (const p of rows) {
    const t = Math.floor(Number(p.ts_unix) / intervalS) * intervalS;
    let b = buckets.get(t);
    if (!b) { b = { ts: t, ups: 0, downs: 0, auths: 0, total: 0, lat: 0, latN: 0 }; buckets.set(t, b); }
    b.total++;
    if (p.status === 'up') b.ups++;
    else if (p.status === 'down') b.downs++;
    else if (p.status === 'auth') b.auths++;
    if (p.status === 'up' && p.latency_ms != null) {
      b.lat += Number(p.latency_ms);
      b.latN++;
    }
  }
  const out = [];
  for (const [t, b] of [...buckets.entries()].sort((a,b)=>a[0]-b[0])) {
    let dominant = 'up';
    if (b.downs >= b.ups && b.downs >= b.auths && b.downs > 0) dominant = 'down';
    else if (b.auths >= b.ups && b.auths > 0) dominant = 'auth';
    out.push({
      ts: t * 1000,
      latency_ms: b.latN > 0 ? Math.round(b.lat / b.latN) : null,
      status: dominant,
      uptime_pct: Math.round(100 * b.ups / b.total)
    });
  }
  return out;
}

const chartPoints = bucket(points, bucketSizeS);

// Detect incidents = consecutive non-up samples
const incidents = [];
let cur = null;
for (const p of points) {
  const tsMs = Number(p.ts_unix) * 1000;
  if (p.status !== 'up') {
    if (!cur) cur = { started_at: tsMs, ended_at: tsMs, status: p.status, error: p.error || null, http_code: p.http_code || null, count: 1 };
    else {
      cur.ended_at = tsMs;
      cur.count++;
      if (p.error && !cur.error) cur.error = p.error;
      if (p.http_code && !cur.http_code) cur.http_code = p.http_code;
      if (p.status === 'down') cur.status = 'down';
    }
  } else if (cur) {
    incidents.push(cur);
    cur = null;
  }
}
if (cur) incidents.push(cur);

const formattedIncidents = incidents.map(i => ({
  started_at: new Date(i.started_at).toISOString(),
  ended_at: new Date(i.ended_at).toISOString(),
  duration_s: Math.max(30, Math.round((i.ended_at - i.started_at) / 1000) + 30),
  status: i.status,
  error: i.error,
  http_code: i.http_code,
  sample_count: i.count
})).reverse();

return [{ json: {
  name: params.name,
  hours: params.hours,
  uptime_1h_pct: stats.uptime_1h != null ? Number(stats.uptime_1h) : null,
  uptime_24h_pct: stats.uptime_24h != null ? Number(stats.uptime_24h) : null,
  uptime_7d_pct: stats.uptime_7d != null ? Number(stats.uptime_7d) : null,
  avg_latency_24h_ms: stats.avg_latency_24h_ms != null ? Number(stats.avg_latency_24h_ms) : null,
  sample_count_7d: stats.sample_count_7d != null ? Number(stats.sample_count_7d) : 0,
  bucket_size_s: bucketSizeS,
  points: chartPoints,
  incidents: formattedIncidents
}}];
